// ============================================
// AuthModal Component - Login & Register
// ============================================

import React, { useState } from 'react';
import { FiX, FiMail, FiLock, FiUser, FiEye, FiEyeOff } from 'react-icons/fi';
import { WiDaySunny } from 'react-icons/wi';
import { useAuth } from '../context/AuthContext';

const AuthModal = ({ onClose }) => {
  const [mode, setMode] = useState('login'); // 'login' or 'register'
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const { login, register } = useAuth();

  const handleChange = (e) => {
    setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));
    setError(''); // Clear error when user types
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (mode === 'login') {
        await login(formData.email, formData.password);
      } else {
        if (!formData.name) {
          setError('Please enter your name');
          setLoading(false);
          return;
        }
        await register(formData.name, formData.email, formData.password);
      }
      onClose(); // Close modal on success
    } catch (err) {
      setError(err.response?.data?.message || 'Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const InputField = ({ icon, name, type, placeholder }) => (
    <div className="relative">
      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-white/40">
        {icon}
      </div>
      <input
        type={name === 'password' ? (showPassword ? 'text' : 'password') : type}
        name={name}
        value={formData[name] || ''}
        onChange={handleChange}
        placeholder={placeholder}
        required
        className="w-full pl-12 pr-12 py-4 bg-white/10 rounded-2xl text-white placeholder-white/40 outline-none focus:ring-2 focus:ring-white/40 border border-white/10 transition-all"
      />
      {name === 'password' && (
        <button type="button" onClick={() => setShowPassword(!showPassword)}
          className="absolute right-4 top-1/2 -translate-y-1/2 text-white/40 hover:text-white">
          {showPassword ? <FiEyeOff /> : <FiEye />}
        </button>
      )}
    </div>
  );

  return (
    // Backdrop
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
      style={{ background: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(8px)' }}>

      {/* Modal */}
      <div className="w-full max-w-md glass-dark rounded-3xl p-8 animate-slide-up relative"
        style={{ background: 'rgba(15, 23, 42, 0.9)', border: '1px solid rgba(255,255,255,0.1)' }}>

        {/* Close Button */}
        <button onClick={onClose}
          className="absolute top-5 right-5 text-white/50 hover:text-white transition-colors">
          <FiX className="text-xl" />
        </button>

        {/* Header */}
        <div className="text-center mb-8">
          <WiDaySunny className="text-yellow-300 text-5xl mx-auto mb-3" />
          <h2 className="text-white text-2xl font-bold">
            {mode === 'login' ? 'Welcome Back! 👋' : 'Create Account ✨'}
          </h2>
          <p className="text-white/50 text-sm mt-1">
            {mode === 'login'
              ? 'Login to save favorites & get personalized weather'
              : 'Join to unlock all features of AI Weather Dashboard'}
          </p>
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-500/20 border border-red-500/30 rounded-xl p-3 mb-4 text-red-300 text-sm text-center">
            ⚠️ {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-4">
          {mode === 'register' && (
            <InputField icon={<FiUser />} name="name" type="text" placeholder="Your full name" />
          )}
          <InputField icon={<FiMail />} name="email" type="email" placeholder="Email address" />
          <InputField icon={<FiLock />} name="password" type="password" placeholder="Password (min 6 characters)" />

          <button
            type="submit"
            disabled={loading}
            className="w-full py-4 bg-gradient-to-r from-blue-500 to-purple-600 rounded-2xl text-white font-semibold text-base hover:from-blue-600 hover:to-purple-700 transition-all disabled:opacity-50 mt-2"
          >
            {loading ? (
              <div className="flex items-center justify-center gap-2">
                <div className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin" />
                <span>{mode === 'login' ? 'Logging in...' : 'Creating account...'}</span>
              </div>
            ) : (
              mode === 'login' ? 'Login' : 'Create Account'
            )}
          </button>
        </form>

        {/* Switch Mode */}
        <p className="text-center text-white/50 text-sm mt-6">
          {mode === 'login' ? "Don't have an account? " : "Already have an account? "}
          <button
            onClick={() => { setMode(mode === 'login' ? 'register' : 'login'); setError(''); }}
            className="text-blue-400 hover:text-blue-300 font-medium"
          >
            {mode === 'login' ? 'Register' : 'Login'}
          </button>
        </p>
      </div>
    </div>
  );
};

export default AuthModal;
